{
  "name": "@node/habit-tracker",
  "version": "1.0.0",
  "description": "Track daily habits with streaks and weekly completion rates",
  "main": "index.ts",
  "modnet": {
    "contentType": "health",
    "structure": "steps",
    "mechanics": ["track"],
    "boundary": "none",
    "scale": 2
