export type Frequency = "daily" | "weekly";

export type Habit = {
  id: string;
  name: string;
  frequency: Frequency;
  createdAt: string;
};

export type CompletionRecord = {
  [date: string]: string[]; // date -> array of completed habit ids
};

export type HabitStore = {
  habits: Habit[];
  completions: CompletionRecord;
};

export type DayStatus = {
  date: string;
  dayLabel: string;
  completed: boolean;
};

export type HabitWeekRow = {
  habit: Habit;
  days: DayStatus[];
  completedCount: number;
  targetCount: number;
};

export type WeeklyStats = {
  rows: HabitWeekRow[];
  overallRate: number;
  weekStart: string;
  weekEnd: string;
};

import type { Habit, CompletionRecord, HabitStore } from "./types";

const HABITS_PATH = `${import.meta.dir}/data/habits.json`;
const COMPLETIONS_PATH = `${import.meta.dir}/data/completions.json`;

const readJson = async <T>(path: string, fallback: T): Promise<T> => {
  const file = Bun.file(path);
  if (!(await file.exists())) return fallback;
  const text = await file.text();
  if (!text.trim()) return fallback;
  return JSON.parse(text) as T;
};

const writeJson = async <T>(path: string, data: T): Promise<void> => {
  await Bun.write(path, JSON.stringify(data, null, 2));
};

export const loadHabits = (): Promise<Habit[]> =>
  readJson<Habit[]>(HABITS_PATH, []);

export const saveHabits = (habits: Habit[]): Promise<void> =>
  writeJson(HABITS_PATH, habits);

export const loadCompletions = (): Promise<CompletionRecord> =>
  readJson<CompletionRecord>(COMPLETIONS_PATH, {});

export const saveCompletions = (completions: CompletionRecord): Promise<void> =>
  writeJson(COMPLETIONS_PATH, completions);

export const loadStore = async (): Promise<HabitStore> => {
  const [habits, completions] = await Promise.all([
    loadHabits(),
    loadCompletions(),
  ]);
  return { habits, completions };
};

import type { Frequency, Habit, CompletionRecord, HabitWeekRow, WeeklyStats } from "./types";
import { loadStore, saveHabits, saveCompletions } from "./store";

const generateId = (): string =>
  crypto.randomUUID().slice(0, 8);

const toDateString = (d: Date): string =>
  d.toISOString().slice(0, 10);

export const today = (): string =>
  toDateString(new Date());

const DAY_LABELS = ["Mon", "Tue", "Wed", "Thu", "Fri", "Sat", "Sun"] as const;

export const getWeekDates = (refDate?: string): { dates: string[]; labels: string[] } => {
  const ref = refDate ? new Date(refDate + "T00:00:00") : new Date();
  const jsDay = ref.getDay(); // 0=Sun
  const mondayOffset = jsDay === 0 ? -6 : 1 - jsDay;
  const monday = new Date(ref);
  monday.setDate(ref.getDate() + mondayOffset);

  const dates: string[] = [];
  const labels: string[] = [];
  for (let i = 0; i < 7; i++) {
    const d = new Date(monday);
    d.setDate(monday.getDate() + i);
    dates.push(toDateString(d));
    labels.push(DAY_LABELS[i]);
  }
  return { dates, labels };
};

export const addHabit = async (name: string, frequency: Frequency): Promise<Habit> => {
  const { habits } = await loadStore();
  const habit: Habit = {
    id: generateId(),
    name,
    frequency,
    createdAt: today(),
  };
  habits.push(habit);
  await saveHabits(habits);
  return habit;
};

export const removeHabit = async (habitId: string): Promise<void> => {
  const { habits } = await loadStore();
  const filtered = habits.filter((h) => h.id !== habitId);
  await saveHabits(filtered);
};

export const toggleCompletion = async (habitId: string, date?: string): Promise<boolean> => {
  const { completions } = await loadStore();
  const d = date ?? today();
  const dayList = completions[d] ?? [];

  const idx = dayList.indexOf(habitId);
  let nowComplete: boolean;
  if (idx >= 0) {
    dayList.splice(idx, 1);
    nowComplete = false;
  } else {
    dayList.push(habitId);
    nowComplete = true;
  }
  completions[d] = dayList;
  await saveCompletions(completions);
  return nowComplete;
};

export const isCompleted = (completions: CompletionRecord, habitId: string, date: string): boolean =>
  (completions[date] ?? []).includes(habitId);

export const getTodayChecklist = async (): Promise<{ habit: Habit; completed: boolean }[]> => {
  const { habits, completions } = await loadStore();
  const d = today();
  return habits.map((habit) => ({
    habit,
    completed: isCompleted(completions, habit.id, d),
  }));
};

export const getWeeklyStats = async (refDate?: string): Promise<WeeklyStats> => {
  const { habits, completions } = await loadStore();
  const { dates, labels } = getWeekDates(refDate);

  let totalTarget = 0;
  let totalCompleted = 0;

  const rows: HabitWeekRow[] = habits.map((habit) => {
    const targetCount = habit.frequency === "daily" ? 7 : 1;
    let completedCount = 0;

    const days = dates.map((date, i) => {
      const completed = isCompleted(completions, habit.id, date);
      if (completed) completedCount++;
      return {
        date,
        dayLabel: labels[i],
        completed,
      };
    });

    totalTarget += targetCount;
    totalCompleted += Math.min(completedCount, targetCount);

    return { habit, days, completedCount, targetCount };
  });

  const overallRate = totalTarget > 0
    ? Math.round((totalCompleted / totalTarget) * 100)
    : 0;

  return {
    rows,
    overallRate,
    weekStart: dates[0],
    weekEnd: dates[6],
  };
};

