    h("input", {
      name: "habitName",
      placeholder: "New habit...",
      style: styles.input,
      required: "true",
    }),
    h("select", { name: "frequency", style: styles.select },
      h("option", { value: "daily" }, "Daily"),
      h("option", { value: "weekly" }, "Weekly"),
    ),
    h("button", { type: "submit", style: styles.addBtn }, "Add"),
