export const renderTodayView = async () => {
  const checklist = await getTodayChecklist();
  const d = today();

  if (checklist.length === 0) {
    return h("div", { style: styles.emptyState },
      h("p", {}, "No habits yet. Add one above to get started."),
    );
  }

  return h(Fragment, {},
    ...checklist.map(({ habit, completed }) =>
      h("div", { style: styles.card },
        h("div", {},
          h("span", { style: styles.habitName }, habit.name),
          h("span", { style: styles.badge }, habit.frequency),
        ),
        h("div", {
          style: completed ? styles.checkboxDone : styles.checkbox,
          "p-trigger": { click: "toggleHabit" },
          "data-habit-id": habit.id,
          "data-date": d,
        }, completed ? "\u2713" : ""),
      ),
    ),
  );
};

const renderWeekRow = (row: HabitWeekRow) =>
  h(Fragment, {},
    h("div", { style: styles.rowName }, row.habit.name),
    ...row.days.map((day) =>
      h("div", {},
        h("div", { style: day.completed ? styles.dotFilled : styles.dot }),
      ),
    ),
  );

export const renderWeekView = async (refDate?: string) => {
  const stats = await getWeeklyStats(refDate);

  if (stats.rows.length === 0) {
    return h("div", { style: styles.emptyState },
      h("p", {}, "No habits to show. Add a habit to see weekly stats."),
    );
  }

  const dayLabels = stats.rows[0].days.map((d) => d.dayLabel);

  return h(Fragment, {},
    h("div", { style: styles.statsBar },
      h("div", { style: styles.rateNumber }, `${stats.overallRate}%`),
      h("div", { style: styles.rateLabel }, `Weekly completion \u00b7 ${stats.weekStart} \u2013 ${stats.weekEnd}`),
      progressBar(stats.overallRate),
    ),
    h("div", { style: styles.weekGrid },
      h("div", {}, ""),
      ...dayLabels.map((label) =>
        h("div", { style: styles.dayHeader }, label),
      ),
      ...stats.rows.flatMap((row) => [renderWeekRow(row)]),
    ),
  );
};

export const renderApp = async (view: "today" | "week" = "today") => {
  const content = view === "today"
    ? await renderTodayView()
    : await renderWeekView();

  return h("div", { style: styles.container },
    h("div", { style: styles.header },
      h("h1", { style: styles.title }, "Habit Tracker"),
      h("div", { style: styles.navGroup },
        h("button", {
