          "p-trigger": { click: "showToday" },
        }, "Today"),
        h("button", {
          style: view === "week" ? styles.navBtnActive : styles.navBtn,
          "p-trigger": { click: "showWeek" },
        }, "Week"),
      ),
    ),
    renderAddForm(),
    h("div", { "p-target": "content" }, content),
  );
};

export const renderToHTML = async (view: "today" | "week" = "today"): Promise<string> => {
  const app = await renderApp(view);
  const ssr = createSSR();
  return ssr(app);
};

export type { Habit, Frequency, CompletionRecord, HabitStore, WeeklyStats } from "./types";
export { loadStore, loadHabits, loadCompletions } from "./store";
export {
  addHabit,
  removeHabit,
  toggleCompletion,
  getTodayChecklist,
  getWeeklyStats,
  today,
  getWeekDates,
} from "./habits";
export {
  renderApp,
  renderTodayView,
  renderWeekView,
  renderToHTML,
  renderAddForm,
} from "./render";

import { addHabit, removeHabit, toggleCompletion } from "./habits";
import { renderToHTML } from "./render";

type View = "today" | "week";

const handleArgs = async () => {
  const args = process.argv.slice(2);
  const command = args[0];

  if (!command || command === "view") {
    const view: View = (args[1] as View) ?? "today";
    const html = await renderToHTML(view);
    console.log(html);
    return;
  }

  if (command === "add") {
    const name = args[1];
    const frequency = (args[2] ?? "daily") as "daily" | "weekly";
    if (!name) {
      console.error("Usage: habit-tracker add <name> [daily|weekly]");
      process.exit(1);
    }
    const habit = await addHabit(name, frequency);
    console.log(`Added habit: ${habit.name} (${habit.frequency}) [${habit.id}]`);
    return;
  }

  if (command === "remove") {
    const id = args[1];
    if (!id) {
      console.error("Usage: habit-tracker remove <habit-id>");
      process.exit(1);
    }
    await removeHabit(id);
    console.log(`Removed habit: ${id}`);
    return;
  }

  if (command === "toggle") {
    const id = args[1];
    const date = args[2];
    if (!id) {
      console.error("Usage: habit-tracker toggle <habit-id> [date]");
      process.exit(1);
    }
    const completed = await toggleCompletion(id, date);
    console.log(`Habit ${id}: ${completed ? "completed" : "uncompleted"}`);
    return;
  }

  console.error(`Unknown command: ${command}`);
  console.error("Commands: view [today|week], add <name> [daily|weekly], remove <id>, toggle <id> [date]");
  process.exit(1);
};

handleArgs();
